import azure.functions as func
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient, PartitionKey
from azure.eventgrid import EventGridPublisherClient, EventGridEvent

def main(myblob: func.InputStream):
    # Azure Storage Blob Configuration
    storage_connection_string = "your_storage_connection_string"
    blob_service_client = BlobServiceClient.from_connection_string(storage_connection_string)
    container_name = "your_container_name"
    blob_client = blob_service_client.get_blob_client(container=container_name, blob=myblob.name)

    # Read the content of the blob
    file_content = myblob.read()

    # Azure Cosmos DB Configuration
    cosmos_db_url = "your_cosmos_db_url"
    cosmos_db_key = "your_cosmos_db_key"
    database_name = "your_database_name"
    container_name = "your_container_name"

    cosmos_client = CosmosClient(cosmos_db_url, credential=cosmos_db_key)
    database = cosmos_client.get_database_client(database_name)
    container = database.get_container_client(container_name)

    # Insert data into Cosmos DB
    item = {
        'id': myblob.name,
        'content': file_content.decode('utf-8')
    }
    container.upsert_item(body=item)

    # Azure Event Grid Configuration
    event_grid_url = "your_event_grid_url"
    event_grid_key = "your_event_grid_key"

    publisher_client = EventGridPublisherClient(event_grid_url, credential=event_grid_key)
    event = EventGridEvent(
        id=myblob.name,
        source="Azure Function",
        subject=myblob.name,
        data={
            'file_name': myblob.name,
            'content_length': len(file_content)
        },
        event_type="FileProcessed"
    )

    publisher_client.send(event)

    return func.HttpResponse(f"Processed blob: {myblob.name}")